package com.hospital.management.dao.impl;import com.hospital.management.dao.PaymentDao;import com.hospital.management.model.Payment;import com.hospital.management.util.DatabaseConnectionManager;import java.math.*;import java.sql.*;import java.util.*;public class PaymentDaoImpl implements PaymentDao{private static final String S="SELECT py.*,u.USERNAME RECEIVED_BY_USERNAME,b.BILL_NUMBER,p.FIRST_NAME||' '||p.LAST_NAME PATIENT_NAME FROM PAYMENTS py JOIN USERS u ON u.USER_ID=py.RECEIVED_BY JOIN BILLS b ON b.BILL_ID=py.BILL_ID JOIN PATIENTS p ON p.PATIENT_ID=b.PATIENT_ID ";public Optional<Payment>findById(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){return find(c,"py.PAYMENT_ID",id);}}public Optional<Payment>findById(Connection c,Long id)throws SQLException{return find(c,"py.PAYMENT_ID",id);}public Optional<Payment>findByPaymentNumber(String n)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){return find(c,"py.PAYMENT_NUMBER",n);}}private Optional<Payment>find(Connection c,String f,Object v)throws SQLException{if(v==null)return Optional.empty();try(PreparedStatement s=c.prepareStatement(S+"WHERE "+f+"=?")){s.setObject(1,v);try(ResultSet r=s.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}}public List<Payment>findByBillId(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+"WHERE py.BILL_ID=? ORDER BY py.PAYMENT_DATE DESC,py.PAYMENT_ID DESC")){s.setLong(1,id);List<Payment>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return x;}}public long createPayment(Connection c,Payment p)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO PAYMENTS(PAYMENT_NUMBER,BILL_ID,PAYMENT_DATE,AMOUNT,PAYMENT_METHOD,TRANSACTION_REFERENCE,STATUS,RECEIVED_BY)VALUES(?,?,CURRENT_TIMESTAMP,?,?,?,?,?)",new String[]{"PAYMENT_ID"})){s.setString(1,p.getPaymentNumber());s.setLong(2,p.getBillId());s.setBigDecimal(3,p.getAmount());s.setString(4,p.getPaymentMethod());s.setString(5,p.getTransactionReference());s.setString(6,p.getStatus());s.setLong(7,p.getReceivedBy());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){if(r.next())return r.getLong(1);throw new SQLException("No payment identifier returned");}}}public boolean updateStatus(Connection c,Long id,String st)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE PAYMENTS SET STATUS=? WHERE PAYMENT_ID=?")){s.setString(1,st);s.setLong(2,id);return s.executeUpdate()==1;}}public BigDecimal calculateSuccessfulPaidAmount(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){return calculateSuccessfulPaidAmount(c,id);}}public BigDecimal calculateSuccessfulPaidAmount(Connection c,Long id)throws SQLException{try(PreparedStatement s=c.prepareStatement("SELECT NVL(SUM(CASE WHEN STATUS='SUCCESS' THEN AMOUNT ELSE 0 END),0) FROM PAYMENTS WHERE BILL_ID=?")){s.setLong(1,id);try(ResultSet r=s.executeQuery()){r.next();return r.getBigDecimal(1);}}}public boolean hasSuccessfulPayments(Long id)throws SQLException{return calculateSuccessfulPaidAmount(id).signum()>0;}private Payment map(ResultSet r)throws SQLException{Payment p=new Payment();p.setPaymentId(r.getLong("PAYMENT_ID"));p.setPaymentNumber(r.getString("PAYMENT_NUMBER"));p.setBillId(r.getLong("BILL_ID"));p.setAmount(r.getBigDecimal("AMOUNT"));p.setPaymentMethod(r.getString("PAYMENT_METHOD"));p.setTransactionReference(r.getString("TRANSACTION_REFERENCE"));p.setStatus(r.getString("STATUS"));p.setReceivedBy(r.getLong("RECEIVED_BY"));p.setReceivedByUsername(r.getString("RECEIVED_BY_USERNAME"));p.setBillNumber(r.getString("BILL_NUMBER"));p.setPatientName(r.getString("PATIENT_NAME"));Timestamp d=r.getTimestamp("PAYMENT_DATE"),c=r.getTimestamp("CREATED_AT");p.setPaymentDate(d==null?null:d.toLocalDateTime());p.setCreatedAt(c==null?null:c.toLocalDateTime());return p;}}
